<?php
/**
 * Currency Converter — Project 6 | FUTM SWE-221
 * Developed by: Aisha | API: Open Exchange Rates
 */

define('APP_ID',   '9069645b9f1f4dc4bb634627a5e6d9d4');
define('BASE_URL', 'https://openexchangerates.org/api');

$CURRENCIES = [
    'NGN' => 'Nigerian Naira',
    'USD' => 'US Dollar',
    'EUR' => 'Euro',
    'GBP' => 'British Pound',
    'GHS' => 'Ghanaian Cedi',
];
$SYMBOLS = ['NGN'=>'\u20a6','USD'=>'$','EUR'=>'\u20ac','GBP'=>'\u00a3','GHS'=>'GH\u20b5'];

$result       = null;
$error        = null;
$amount       = 1;
$fromCurrency = 'NGN';
$toCurrency   = 'USD';

if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['convert'])) {
    $amount       = floatval($_POST['amount'] ?? 1);
    $fromCurrency = strtoupper(trim($_POST['from_currency'] ?? 'NGN'));
    $toCurrency   = strtoupper(trim($_POST['to_currency']   ?? 'USD'));

    if ($amount <= 0) {
        $error = 'Please enter an amount greater than zero.';
    } elseif ($fromCurrency === $toCurrency) {
        $error = 'Please choose two different currencies.';
    } else {
        $symbols = implode(',', array_unique([$fromCurrency, $toCurrency]));
        $url     = BASE_URL . '/latest.json?app_id=' . APP_ID . '&symbols=' . $symbols;

        $ch = curl_init();
        curl_setopt_array($ch, [
            CURLOPT_URL            => $url,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_TIMEOUT        => 10,
            CURLOPT_SSL_VERIFYPEER => true,
        ]);
        $raw  = curl_exec($ch);
        $code = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        $err  = curl_error($ch);
        curl_close($ch);

        if ($err) {
            $error = 'Connection failed: ' . $err;
        } elseif ($code !== 200) {
            $d = json_decode($raw, true);
            $error = $d['description'] ?? $d['message'] ?? 'API error (HTTP ' . $code . ')';
        } else {
            $data     = json_decode($raw, true);
            $rates    = $data['rates'] ?? [];
            $rateFrom = $rates[$fromCurrency] ?? null;
            $rateTo   = $rates[$toCurrency]   ?? null;

            if ($rateFrom && $rateTo && $rateFrom != 0) {
                $converted = $amount * ($rateTo / $rateFrom);
                $result = [
                    'amount'    => $amount,
                    'from'      => $fromCurrency,
                    'to'        => $toCurrency,
                    'converted' => $converted,
                    'rate'      => $rateTo / $rateFrom,
                    'updated'   => isset($data['timestamp'])
                                    ? date('d M Y, H:i T', $data['timestamp']) : 'N/A',
                ];
            } else {
                $error = 'Rate not available for this pair.';
            }
        }
    }
}
?>
