<script>
function sw() {
  const f=document.getElementById('from_currency'),
        t=document.getElementById('to_currency'),v=f.value;
  f.value=t.value; t.value=v;
}
document.getElementById('frm').addEventListener('submit',function(e){
  const f=document.getElementById('from_currency').value,
        t=document.getElementById('to_currency').value,
        a=parseFloat(document.getElementById('amount').value);
  if(f===t){e.preventDefault();alert('Choose two different currencies.');}
  else if(isNaN(a)||a<=0){e.preventDefault();alert('Enter a valid amount > 0.');}
});
</script>
